<?php
declare(strict_types=1);
require_once __DIR__.'/../includes/ecosystem.php';$wallet=beyond_app_bootstrap('DailyBreath');$pdo=beyond_db();$userId=(int)$_SESSION['user_id'];
$catalog=[
 'preschool'=>['Preschool','🧸',['God Made Me and Loves Me','Bible Heroes','Jesus Loves Children','Prayer and Kindness','Worship and Thankfulness']],
 'kids'=>['Kids','🌱',['The Ten Commandments','Bible Foundations','The Life of Jesus','Prayer and Faith','Living with Courage']],
 'preteen'=>['Preteen','📖',['Ten Commandments in Real Life','Identity and Purpose','Wisdom and Choices','The Life and Teaching of Jesus','Faith in Action']],
 'teen'=>['Teen','✨',['Identity in Christ','Relationships and Integrity','Questions, Doubt, and Faith','Purpose and Leadership','Faith in Culture']],
 'adult'=>['Adult','🕊️',['Bible Foundations','Spiritual Disciplines','Relationships and Calling','Biblical Wisdom for Life','Faithful Leadership']],
];
// Portable catalog bootstrap keeps MySQL and SQLite installations aligned.
try{foreach($catalog as $ageSlug=>[$ageName,$icon,$modules]){
  $a=$pdo->prepare('SELECT id FROM academy_age_groups WHERE slug=?');$a->execute([$ageSlug]);$ageId=(int)$a->fetchColumn();if(!$ageId)continue;
  foreach($modules as $offset=>$title){$number=$offset+1;$slug=$ageSlug.'-module-'.$number;$q=$pdo->prepare('SELECT id FROM academy_courses WHERE slug=?');$q->execute([$slug]);$courseId=(int)$q->fetchColumn();
    if(!$courseId){$pdo->prepare('INSERT INTO academy_courses(slug,title,summary,is_free,is_published,sort_order) VALUES(?,?,?,?,1,?)')->execute([$slug,$title,"Ten guided lessons for the $ageName learning path.",$number===1?1:0,($ageId*10)+$number]);$courseId=(int)$pdo->lastInsertId();}
    $m=$pdo->prepare('SELECT 1 FROM academy_course_age_groups WHERE course_id=? AND age_group_id=?');$m->execute([$courseId,$ageId]);if(!$m->fetchColumn())$pdo->prepare('INSERT INTO academy_course_age_groups(course_id,age_group_id) VALUES(?,?)')->execute([$courseId,$ageId]);
    for($lesson=1;$lesson<=10;$lesson++){$l=$pdo->prepare('SELECT 1 FROM academy_lessons WHERE course_id=? AND lesson_number=?');$l->execute([$courseId,$lesson]);if(!$l->fetchColumn())$pdo->prepare('INSERT INTO academy_lessons(course_id,lesson_number,title,lesson_type,is_preview,is_published) VALUES(?,?,?,\'reading\',?,1)')->execute([$courseId,$lesson,$title.' · Lesson '.$lesson,$number===1?1:0]);}
  }
}}catch(Throwable $e){error_log('Academy catalog bootstrap: '.$e->getMessage());}
$subscribed=false;try{$s=$pdo->prepare("SELECT 1 FROM academy_subscriptions WHERE user_id=? AND status IN ('active','trialing') AND (current_period_end IS NULL OR current_period_end>=CURRENT_TIMESTAMP) LIMIT 1");$s->execute([$userId]);$subscribed=(bool)$s->fetchColumn();}catch(Throwable $e){}
$selected=$_GET['age']??'preteen';if(!isset($catalog[$selected]))$selected='preteen';
$s=$pdo->prepare('SELECT c.* FROM academy_courses c JOIN academy_course_age_groups m ON m.course_id=c.id JOIN academy_age_groups a ON a.id=m.age_group_id WHERE a.slug=? AND c.is_published=1 ORDER BY c.sort_order,c.id');$s->execute([$selected]);$courses=$s->fetchAll(PDO::FETCH_ASSOC);
?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Bible Academy | DailyBreath</title><style>*{box-sizing:border-box}body{margin:0;padding-bottom:100px;color:#eef5ed;font-family:Inter,system-ui;background:linear-gradient(#00180c55,#00180cb5),url('../assets/dailybreath-login-background.webp') center top/cover fixed}.shell{max-width:1050px;margin:auto;padding:48px 22px 80px}.top{display:flex;justify-content:space-between}.top a{color:#f0cf7e}.hero{padding:50px 0 25px}.eyebrow{color:#f0cf7e;font-weight:900;letter-spacing:.12em;font-size:12px}.hero h1{font:500 clamp(46px,8vw,76px)/1 Georgia,serif;margin:12px 0}.hero p{max-width:720px;color:#dce6dc;font-size:18px;line-height:1.6}.ages{display:grid;grid-template-columns:repeat(5,1fr);gap:9px;margin:18px 0 26px}.ages a{padding:15px 8px;border:1px solid #ffffff44;border-radius:15px;color:#173f2c;background:#fffdf3e8;text-align:center;text-decoration:none}.ages a.active{background:#f0cf7e}.ages span,.ages strong{display:block}.modules{display:grid;gap:14px}.module{display:grid;grid-template-columns:65px 1fr auto;gap:17px;align-items:center;padding:23px;border:1px solid #ffffff66;border-radius:22px;color:#263228;background:#fffdf7f2;box-shadow:0 20px 60px #00170b55}.num{display:grid;place-items:center;width:56px;height:56px;border-radius:17px;color:#fff;background:#173f2c;font-size:23px;font-weight:900}.module h2{margin:0 0 6px}.module p{margin:0;color:#68736c}.meta{margin-top:9px;color:#6f842e;font-size:12px;font-weight:900}.btn{display:inline-flex;padding:12px 16px;border-radius:12px;color:#173f2c;background:#f0cf7e;text-decoration:none;font-weight:900}.locked{color:#fff;background:#173f2c}.pricing{margin:24px 0;padding:21px;border-radius:20px;background:#0b3927dd;border:1px solid #ffffff44}.pricing strong{color:#f0cf7e}@media(max-width:760px){body{background-attachment:scroll}.ages{grid-template-columns:repeat(2,1fr)}.module{grid-template-columns:50px 1fr}.module .btn{grid-column:1/-1;justify-content:center}}</style></head><body><main class="shell"><header class="top"><strong>DailyBreath · Bible Academy</strong><a href="index.php">← Home</a></header><section class="hero"><span class="eyebrow">5 AGE PATHS · 5 MODULES EACH</span><h1>Grow deeper at every age.</h1><p>Each module includes ten lessons, a ten-question test after every lesson, and a cumulative module exam. Module 1 is free for every age group.</p></section><nav class="ages" aria-label="Choose an age group"><?php foreach($catalog as $slug=>[$name,$icon]):?><a class="<?=$slug===$selected?'active':''?>" href="?age=<?=e($slug)?>"><span><?=$icon?></span><strong><?=e($name)?></strong></a><?php endforeach;?></nav><section class="pricing"><strong><?= $subscribed?'All modules unlocked':'Module 1 is free' ?></strong><p><?= $subscribed?'Your Academy subscription is active.':'Continue to Modules 2–5 with the $4.99/month Academy subscription.' ?></p><?php if($subscribed):?><form method="post" action="academy-manage.php"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><button class="btn" type="submit">Manage subscription</button></form><?php endif;?></section><section class="modules"><?php foreach($courses as $index=>$course):$number=$index+1;$locked=!(bool)$course['is_free']&&!$subscribed;$q=$pdo->prepare('SELECT COUNT(DISTINCT lesson_id) FROM academy_quiz_attempts WHERE user_id=? AND passed=1 AND lesson_id IN(SELECT id FROM academy_lessons WHERE course_id=?)');$q->execute([$userId,$course['id']]);$passedLessons=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT 1 FROM academy_module_exam_attempts WHERE user_id=? AND course_id=? AND passed=1 LIMIT 1');$q->execute([$userId,$course['id']]);$examPassed=(bool)$q->fetchColumn();?><article class="module"><span class="num"><?=$number?></span><div><h2><?=e($course['title'])?></h2><p><?=e($course['summary'])?></p><div class="meta">10 LESSONS · 10 TESTS · 1 MODULE EXAM · <?=$passedLessons?>/10 LESSON TESTS PASSED<?=$examPassed?' · EXAM PASSED':''?><?=!empty($course['is_free'])?' · FREE':''?></div></div><a class="btn <?=$locked?'locked':''?>" href="<?=$locked?'academy-subscribe.php':'course.php?course='.rawurlencode($course['slug']).'&lesson=1'?>"><?=$locked?'Unlock module':($passedLessons?'Keep learning':'Begin module')?></a></article><?php endforeach;?></section></main></body></html>
